55	func (s *service) listModelsForSubprocessHarness(filter ModelFilter) []ModelInfo {
56		name := harnesses.ResolveHarnessAlias(filter.Harness)
57		cfg, ok := s.registry.Get(name)
58		modelIDs := subprocessHarnessModelIDs(name, cfg)
59		if !ok || harnessRunsInProcessOrHTTP(cfg) || len(modelIDs) == 0 {
60			return nil
61		}
62		if filter.Provider != "" && filter.Provider != name {
63			return nil
64		}
65		cat, _ := modelcatalog.Default()
66		out := make([]ModelInfo, 0, len(modelIDs))
67		for i, id := range modelIDs {
68			info := ModelInfo{
69				ID:             id,
70				Provider:       name,
71				Harness:        name,
72				EndpointName:   name,
73				ServerInstance: name,
74				Capabilities:   []string{"streaming", "tool_use"},
75				Available:      true,
76				IsDefault:      cfg.DefaultModel != "" && id == cfg.DefaultModel,
77				Billing:        harnessPaymentKind(name, cfg),
78				RankPosition:   i,
79			}
80			if cat != nil {
81				info.ContextLength, info.ContextSource = resolveContextEvidence(context.Background(), ServiceProviderEntry{}, id, cat)
82				info.Cost, info.PerfSignal = catalogCostAndPerf(cat, id)
83				info.Power, info.AutoRoutable, info.ExactPinOnly = catalogPowerEligibility(cat, id)
84			}
85			info.Utilization = s.routeUtilizationEvidence(name, info.ServerInstance, info.EndpointName, id)
86			out = append(out, info)
87		}
88		return out
89	}
