219	func (s *service) modelInfoFromSnapshotModel(ctx context.Context, providerName string, entry ServiceProviderEntry, defaultProviderName string, cat *modelcatalog.Catalog, model modelsnapshot.KnownModel, rankPosition int) ModelInfo {
220		info := ModelInfo{
221			ID:              model.ID,
222			Provider:        providerName,
223			ProviderType:    model.ProviderType,
224			Harness:         model.Harness,
225			EndpointName:    model.EndpointName,
226			EndpointBaseURL: model.EndpointBaseURL,
227			ServerInstance:  model.ServerInstance,
228			ContextLength:   model.ContextWindow,
229			Utilization:     s.routeUtilizationEvidence(providerName, model.ServerInstance, model.EndpointName, model.ID),
230			Capabilities:    providerCapabilities(entry),
231			Cost: CostInfo{
232				InputPerMTok:  model.CostInputPerM,
233				OutputPerMTok: model.CostOutputPerM,
234			},
235			Power:                         model.Power,
236			AutoRoutable:                  model.AutoRoutable,
237			ExactPinOnly:                  model.ExactPinOnly,
238			Billing:                       model.Billing,
239			ActualCashSpend:               model.ActualCashSpend,
240			EffectiveCost:                 model.EffectiveCost,
241			EffectiveCostSource:           model.EffectiveCostSource,
242			SupportsTools:                 model.SupportsTools,
243			DeploymentClass:               model.DeploymentClass,
244			HealthFreshnessAt:             model.HealthFreshnessAt,
245			HealthFreshnessSource:         model.HealthFreshnessSource,
246			QuotaFreshnessAt:              model.QuotaFreshnessAt,
247			QuotaFreshnessSource:          model.QuotaFreshnessSource,
248			ModelDiscoveryFreshnessAt:     model.DiscoveredAt,
249			ModelDiscoveryFreshnessSource: string(model.DiscoveredVia),
250			Available:                     true,
251			RankPosition:                  rankPosition,
252		}
253		if info.Harness == "" {
254			info.Harness = "fiz"
255		}
256		info.ContextLength, info.ContextSource = resolveContextEvidence(ctx, entry, model.ID, cat)
257		if cat != nil {
258			_, info.PerfSignal = catalogCostAndPerf(cat, model.ID)
259		}
260		info.IsDefault = providerName == defaultProviderName && entry.Model != "" && model.ID == entry.Model
261		return info
262	}
