264	type modelDiscoveryEndpoint struct {
265		Name           string
266		BaseURL        string
267		ServerInstance string
268	}
269	
270	func modelDiscoveryEndpoints(entry ServiceProviderEntry) []modelDiscoveryEndpoint {
271		if len(entry.Endpoints) > 0 {
272			out := make([]modelDiscoveryEndpoint, 0, len(entry.Endpoints))
273			for _, ep := range entry.Endpoints {
274				if strings.TrimSpace(ep.BaseURL) == "" {
275					continue
276				}
277				out = append(out, modelDiscoveryEndpoint{
278					Name:           endpointDisplayName(ep.Name, ep.BaseURL),
279					BaseURL:        ep.BaseURL,
280					ServerInstance: serverinstance.Normalize(ep.BaseURL, ep.ServerInstance),
281				})
282			}
283			return out
284		}
285		if strings.TrimSpace(entry.BaseURL) == "" {
286			return nil
287		}
288		return []modelDiscoveryEndpoint{{
289			Name:           endpointDisplayName("default", entry.BaseURL),
290			BaseURL:        entry.BaseURL,
291			ServerInstance: serverinstance.Normalize(entry.BaseURL, entry.ServerInstance),
292		}}
293	}
294	
295	func endpointDisplayName(name, baseURL string) string {
296		if trimmed := strings.TrimSpace(name); trimmed != "" {
297			return trimmed
298		}
299		u, err := url.Parse(baseURL)
300		if err == nil && u.Host != "" {
301			return u.Host
302		}
303		return "default"
304	}
