354	// catalogCostAndPerf extracts CostInfo and PerfSignal for a model from the catalog.
355	func catalogCostAndPerf(cat *modelcatalog.Catalog, modelID string) (CostInfo, PerfSignal) {
356		entry, ok := cat.LookupModel(modelID)
357		if !ok {
358			return CostInfo{}, PerfSignal{}
359		}
360		return CostInfo{
361				InputPerMTok:  catalogEntryInputCost(entry),
362				OutputPerMTok: catalogEntryOutputCost(entry),
363			}, PerfSignal{
364				SpeedTokensPerSec: entry.SpeedTokensPerSec,
365				SWEBenchVerified:  entry.SWEBenchVerified,
366			}
367	}
368	
369	func catalogPowerEligibility(cat *modelcatalog.Catalog, modelID string) (int, bool, bool) {
370		eligibility, ok := cat.ModelEligibility(modelID)
371		if !ok {
372			return 0, false, false
373		}
374		return eligibility.Power, eligibility.AutoRoutable, eligibility.ExactPinOnly
375	}
376	
377	// catalogPowerForModel returns the catalog-projected power for a model
378	// (CONTRACT-003 § Catalog Power Projection). Returns 0 when the catalog
379	// is nil or the model has no entry, which the contract documents as
380	// "unknown / exact-pin-only / no catalog entry" for the
381	// ServiceRoutingActual.Power surface.
382	func catalogPowerForModel(cat *modelcatalog.Catalog, modelID string) int {
383		if cat == nil || modelID == "" {
384			return 0
385		}
386		power, _, _ := catalogPowerEligibility(cat, modelID)
387		return power
388	}
389	
390	func catalogEntryInputCost(entry modelcatalog.ModelEntry) float64 {
391		if entry.CostInputPerM != 0 {
392			return entry.CostInputPerM
393		}
394		return entry.CostInputPerMTok
395	}
396	
397	func catalogEntryOutputCost(entry modelcatalog.ModelEntry) float64 {
398		if entry.CostOutputPerM != 0 {
399			return entry.CostOutputPerM
400		}
401		return entry.CostOutputPerMTok
402	}
403	
404	// providerCapabilities returns the capability set for a provider entry.
405	func providerCapabilities(entry ServiceProviderEntry) []string {
406		switch normalizeServiceProviderType(entry.Type) {
407		case "anthropic":
408			return []string{"tool_use", "vision", "streaming"}
409		case "omlx":
410			return []string{"tool_use", "streaming", "json_mode", "reasoning_control"}
411		default:
412			return []string{"tool_use", "streaming", "json_mode"}
413		}
414	}
