260	// ReadClaudeQuotaRoutingDecision is a convenience wrapper that reads the
261	// default cache and produces a routing decision in one call. It is the
262	// entry point foreground routing should use instead of any inline PTY
263	// capture.
264	func ReadClaudeQuotaRoutingDecision(now time.Time, staleAfter time.Duration) ClaudeQuotaRoutingDecision {
265		snap, _ := ReadClaudeQuota()
266		return DecideClaudeQuotaRouting(snap, now, staleAfter)
267	}
