269	// IsClaudeQuotaExhaustedMessage recognizes Claude CLI quota failures that are
270	// emitted as plain text rather than structured quota data. Claude currently
271	// reports weekly exhaustion with wording like "out of extra usage", so callers
272	// must treat these strings as a hard quota signal.
273	func IsClaudeQuotaExhaustedMessage(text string) bool {
274		normalized := strings.ToLower(strings.TrimSpace(text))
275		return strings.Contains(normalized, "out of extra usage") ||
276			strings.Contains(normalized, "usage limit reached") ||
277			strings.Contains(normalized, "quota exhausted") ||
278			strings.Contains(normalized, "weekly quota") ||
279			strings.Contains(normalized, "current week") && strings.Contains(normalized, "exhaust")
280	}
281	
282	// MarkClaudeQuotaExhaustedFromMessage records a runtime Claude quota failure
283	// in the durable cache so later automatic routing avoids Claude until a fresh
284	// quota probe proves headroom again.
285	func MarkClaudeQuotaExhaustedFromMessage(text string, now time.Time) bool {
286		if !IsClaudeQuotaExhaustedMessage(text) {
287			return false
288		}
289		path, err := ClaudeQuotaCachePath()
290		if err != nil {
291			return true
292		}
293		if now.IsZero() {
294			now = time.Now()
295		}
296		snap := ClaudeQuotaSnapshot{
297			CapturedAt:        now.UTC(),
298			FiveHourLimit:     100,
299			FiveHourRemaining: 0,
300			WeeklyLimit:       100,
301			WeeklyRemaining:   0,
302			Windows: []harnesses.QuotaWindow{
303				{Name: "Current week (all models)", LimitID: "weekly-all", WindowMinutes: 10080, UsedPercent: 100, State: "exhausted"},
304				{Name: "Extra usage", LimitID: "extra", UsedPercent: 100, State: "exhausted"},
305			},
306			Source:  "runtime_error",
307			Account: &harnesses.AccountInfo{PlanType: "unknown"},
308		}
309		_ = WriteClaudeQuota(path, snap)
310		return true
311	}
312	
313	// RefreshClaudeQuotaAsync launches a background goroutine that invokes
314	// capture and writes the result to the default cache path. It returns
315	// immediately; callers never block on capture.
316	//
317	// The capture function is injected so that the durable cache layer does
318	// not depend on any specific PTY implementation. A future `ddx claude
319	// refresh-quota` subcommand can pass a real PTY-backed capture; tests can
320	// pass deterministic fakes.
321	//
322	// If capture returns an error, the cache is not touched.
323	func RefreshClaudeQuotaAsync(capture func() (ClaudeQuotaSnapshot, error)) {
324		if capture == nil {
325			return
326		}
327		go func() {
328			snap, err := capture()
329			if err != nil {
330				return
331			}
332			path, pathErr := ClaudeQuotaCachePath()
333			if pathErr != nil {
334				return
335			}
336			_ = WriteClaudeQuota(path, snap)
337		}()
338	}
