138	func claudeCLIExecutableModel(model string) string {
139		normalized := strings.ToLower(strings.TrimSpace(model))
140		switch {
141		case normalized == "sonnet" || strings.HasPrefix(normalized, "sonnet-") || strings.HasPrefix(normalized, "claude-sonnet-"):
142			return "sonnet"
143		case normalized == "opus" || strings.HasPrefix(normalized, "opus-") || strings.HasPrefix(normalized, "claude-opus-"):
144			return "opus"
145		case normalized == "haiku" || strings.HasPrefix(normalized, "haiku-") || strings.HasPrefix(normalized, "claude-haiku-"):
146			return "haiku"
147		default:
148			return model
149		}
150	}
