306	// resolveContextEvidence resolves the context window for a model using the
307	// precedence chain: provider config > provider API > catalog > default.
308	func resolveContextEvidence(ctx context.Context, entry ServiceProviderEntry, modelID string, cat *modelcatalog.Catalog) (int, string) {
309		modelID = strings.TrimSpace(modelID)
310		if modelID == "" {
311			return 0, ContextSourceUnknown
312		}
313		if entry.ContextWindow > 0 {
314			return entry.ContextWindow, ContextSourceProviderConfig
315		}
316		if limits, source := providerAPIContextEvidence(ctx, entry, modelID); limits > 0 {
317			return limits, source
318		}
319		if cat != nil {
320			if n := cat.ContextWindowForModel(modelID); n > 0 {
321				return n, ContextSourceCatalog
322			}
323		}
324		return compaction.DefaultContextWindow, ContextSourceDefault
325	}
326	
327	func providerAPIContextEvidence(ctx context.Context, entry ServiceProviderEntry, modelID string) (int, string) {
328		switch entry.Type {
329		case "lmstudio":
330			if entry.BaseURL == "" {
331				return 0, ""
332			}
333			if limits := lmstudio.LookupModelLimits(ctx, entry.BaseURL, modelID); limits.ContextLength > 0 {
334				return limits.ContextLength, ContextSourceProviderAPI
335			}
336		case "omlx":
337			if entry.BaseURL == "" {
338				return 0, ""
339			}
340			if limits := omlx.LookupModelLimits(ctx, entry.BaseURL, modelID); limits.ContextLength > 0 {
341				return limits.ContextLength, ContextSourceProviderAPI
342			}
343		case "openrouter":
344			if entry.BaseURL == "" {
345				return 0, ""
346			}
347			if limits := openrouter.LookupModelLimits(ctx, entry.BaseURL, entry.APIKey, entry.Headers, modelID); limits.ContextLength > 0 {
348				return limits.ContextLength, ContextSourceProviderAPI
349			}
350		}
351		return 0, ""
352	}
