13	type subscriptionQuotaView struct {
14		OK          bool
15		Present     bool
16		Fresh       bool
17		Windows     []harnesses.QuotaWindow
18		PercentUsed int
19		Trend       string
20		Reason      string
21	}
22	
23	func subscriptionQuotaForHarness(name string, now time.Time) (subscriptionQuotaView, bool) {
24		switch name {
25		case "claude":
26			dec := claudeharness.ReadClaudeQuotaRoutingDecision(now, 0)
27			view := subscriptionQuotaView{
28				OK:      dec.PreferClaude,
29				Present: dec.SnapshotPresent,
30				Fresh:   dec.Fresh,
31				Reason:  dec.Reason,
32				Trend:   routing.QuotaTrendUnknown,
33			}
34			if dec.Snapshot != nil {
35				view.Windows = append([]harnesses.QuotaWindow(nil), dec.Snapshot.Windows...)
36				view.PercentUsed = int(claudeQuotaMaxUsedPercent(dec.Snapshot))
37				view.Trend = quotaTrend(view.PercentUsed, dec.Fresh)
38			}
39			return view, true
40		case "codex":
41			dec := codexharness.ReadCodexQuotaRoutingDecision(now, 0)
42			view := subscriptionQuotaView{
43				OK:      dec.PreferCodex,
44				Present: dec.SnapshotPresent,
45				Fresh:   dec.Fresh,
46				Reason:  dec.Reason,
47				Trend:   routing.QuotaTrendUnknown,
48			}
49			if dec.Snapshot != nil {
50				view.Windows = append([]harnesses.QuotaWindow(nil), dec.Snapshot.Windows...)
51				view.PercentUsed = int(maxQuotaWindowUsedPercent(dec.Snapshot.Windows))
52				view.Trend = quotaTrend(view.PercentUsed, dec.Fresh)
53			}
54			return view, true
55		case "gemini":
56			dec := geminiharness.ReadGeminiQuotaRoutingDecision(now, 0)
57			view := subscriptionQuotaView{
58				OK:      dec.PreferGemini,
59				Present: dec.SnapshotPresent,
60				Fresh:   dec.Fresh,
61				Reason:  dec.Reason,
62				Trend:   routing.QuotaTrendUnknown,
63			}
64			if dec.Snapshot != nil {
65				view.Windows = append([]harnesses.QuotaWindow(nil), dec.Snapshot.Windows...)
66				view.PercentUsed = int(dec.Snapshot.MaxUsedPercent())
67				if len(dec.ExhaustedTiers) > 0 && len(dec.AvailableTiers) == 0 {
68					view.Trend = routing.QuotaTrendExhausting
69				} else {
70					view.Trend = quotaTrend(view.PercentUsed, dec.Fresh)
71				}
72			}
73			return view, true
74		default:
75			return subscriptionQuotaView{}, false
76		}
77	}
78	
79	func claudeQuotaMaxUsedPercent(snap *claudeharness.ClaudeQuotaSnapshot) float64 {
80		if snap == nil {
81			return 0
82		}
83		maxUsed := 0.0
84		if snap.FiveHourLimit > 0 {
85			maxUsed = float64(snap.FiveHourLimit-snap.FiveHourRemaining) / float64(snap.FiveHourLimit) * 100
86		}
87		if snap.WeeklyLimit > 0 {
88			weeklyUsed := float64(snap.WeeklyLimit-snap.WeeklyRemaining) / float64(snap.WeeklyLimit) * 100
89			if weeklyUsed > maxUsed {
90				maxUsed = weeklyUsed
91			}
92		}
93		if windowMax := maxQuotaWindowUsedPercent(snap.Windows); windowMax > maxUsed {
94			maxUsed = windowMax
95		}
96		return maxUsed
97	}
98	
99	func maxQuotaWindowUsedPercent(windows []harnesses.QuotaWindow) float64 {
100		maxUsed := 0.0
101		for _, window := range windows {
102			if window.UsedPercent > maxUsed {
103				maxUsed = window.UsedPercent
104			}
105		}
106		return maxUsed
107	}
108	
109	func quotaTrend(percentUsed int, fresh bool) string {
110		switch {
111		case percentUsed >= 90:
112			return routing.QuotaTrendExhausting
113		case percentUsed >= 70:
114			return routing.QuotaTrendBurning
115		case fresh:
116			return routing.QuotaTrendHealthy
117		default:
118			return routing.QuotaTrendUnknown
119		}
120	}
