59	// SetCaptureForTest swaps the package-level PTY probe used by
60	// Runner.RefreshQuota and returns a restore function. Production code
61	// MUST NOT call this — it exists so service-level tests can inject
62	// deterministic PTY responses while exercising the real cache I/O
63	// inside Runner.refreshQuotaLocked. The call also forgets any
64	// in-flight RefreshQuota cohort so the next caller runs a fresh
65	// single-flight execution against the new probe instead of piggybacking
66	// on a prior test's probe.
67	func SetCaptureForTest(fn QuotaProbeFunc) func() {
68		prev := captureQuotaProbe
69		captureQuotaProbe = fn
70		refreshGroup.Forget("claude:refresh-quota")
71		return func() {
72			captureQuotaProbe = prev
73			refreshGroup.Forget("claude:refresh-quota")
74		}
75	}
