229	// claudeQuotaStatusFromSnapshot projects the per-harness snapshot onto
230	// harnesses.QuotaStatus, deriving State and RoutingPreference via the
231	// existing DecideClaudeQuotaRouting helper so today's "PreferClaude +
232	// freshness" semantics map cleanly onto CONTRACT-004's RoutingPreference
233	// enum.
234	func claudeQuotaStatusFromSnapshot(snap *ClaudeQuotaSnapshot, now time.Time) harnesses.QuotaStatus {
235		decision := DecideClaudeQuotaRouting(snap, now, claudeQuotaFreshness)
236		pref, state := mapClaudeRoutingPreference(decision)
237		status := harnesses.QuotaStatus{
238			Source:            snap.Source,
239			CapturedAt:        snap.CapturedAt,
240			Fresh:             decision.Fresh,
241			Age:               decision.Age,
242			State:             state,
243			Windows:           append([]harnesses.QuotaWindow(nil), snap.Windows...),
244			RoutingPreference: pref,
245			Reason:            quotaReasonForProjection(decision, state),
246		}
247		if snap.Account != nil {
248			acct := claudeAccountSnapshotFromQuotaSnapshot(snap, now)
249			status.Account = &acct
250		}
251		return status
252	}
253	
254	// quotaReasonForProjection trims the routing decision's diagnostic
255	// reason so QuotaStatus.Reason carries information only when it adds
256	// value beyond the State enum. The trivial QuotaOK success path
257	// ("fresh snapshot has headroom") is suppressed so the public Status
258	// string matches the contract-003 fixture (bare "ok"). All non-OK
259	// states keep the decision reason because it surfaces why the state is
260	// not ok (stale snapshot, incomplete account, exhausted window).
261	func quotaReasonForProjection(decision ClaudeQuotaRoutingDecision, state harnesses.QuotaStateValue) string {
262		if state == harnesses.QuotaOK {
263			return ""
264		}
265		return decision.Reason
266	}
267	
268	// mapClaudeRoutingPreference translates today's PreferClaude+freshness
269	// decision into the CONTRACT-004 (RoutingPreference, QuotaStateValue)
270	// pair. Legacy semantics: missing snapshot ⇒ Unavailable/Unknown;
271	// stale ⇒ Stale/Blocked ("assume limited"); fresh+PreferClaude ⇒
272	// OK/Available; fresh+!PreferClaude ⇒ Blocked/Blocked.
273	func mapClaudeRoutingPreference(d ClaudeQuotaRoutingDecision) (harnesses.RoutingPreference, harnesses.QuotaStateValue) {
274		if !d.SnapshotPresent {
275			return harnesses.RoutingPreferenceUnknown, harnesses.QuotaUnavailable
276		}
277		if !d.Fresh {
278			return harnesses.RoutingPreferenceBlocked, harnesses.QuotaStale
279		}
280		if d.PreferClaude {
281			return harnesses.RoutingPreferenceAvailable, harnesses.QuotaOK
282		}
283		return harnesses.RoutingPreferenceBlocked, harnesses.QuotaBlocked
284	}
285	
286	// claudeAccountSnapshotFromQuotaSnapshot derives an AccountSnapshot from
287	// the quota cache's embedded Account field. Plan-type "unknown" (written
288	// by MarkClaudeQuotaExhaustedFromMessage on runtime errors) is reported
289	// as unauthenticated evidence rather than positive authentication.
290	func claudeAccountSnapshotFromQuotaSnapshot(snap *ClaudeQuotaSnapshot, now time.Time) harnesses.AccountSnapshot {
291		out := harnesses.AccountSnapshot{
292			Source:     "cache",
293			CapturedAt: snap.CapturedAt,
294			Fresh:      IsClaudeQuotaFresh(snap, now, claudeAccountFreshness),
295		}
296		if snap.Account == nil {
297			return out
298		}
299		plan := strings.TrimSpace(snap.Account.PlanType)
300		out.PlanType = plan
301		out.Email = snap.Account.Email
302		out.OrgName = snap.Account.OrgName
303		switch {
304		case plan == "" || strings.EqualFold(plan, "unknown"):
305			out.Unauthenticated = true
306		default:
307			out.Authenticated = true
308		}
309		return out
310	}
