88	func (s *service) ensurePrimaryQuotaRefresh(ctx context.Context, mode quotaRefreshMode) {
89		policy := s.quotaRefreshPolicy()
90		var waits []<-chan struct{}
91		for _, name := range []string{"claude", "codex"} {
92			status := s.primaryQuotaCacheStatus(ctx, name, policy.debounce)
93			if !status.needsRefresh {
94				continue
95			}
96			done := s.requestPrimaryQuotaRefresh(ctx, name, policy)
97			if mode == quotaRefreshStartup && !status.usable && done != nil {
98				waits = append(waits, done)
99			}
100		}
101		if mode == quotaRefreshStartup && len(waits) > 0 && policy.startupWait > 0 {
102			waitForPrimaryQuotaRefreshes(waits, policy.startupWait)
103		}
104	}
