106	func (s *service) quotaRefreshPolicy() quotaRefreshPolicy {
107		policy := quotaRefreshPolicy{
108			debounce:     defaultQuotaRefreshDebounce,
109			startupWait:  defaultQuotaRefreshStartupWait,
110			probeTimeout: defaultQuotaRefreshProbeTimeout,
111		}
112		if s != nil {
113			if s.opts.QuotaRefreshDebounce > 0 {
114				policy.debounce = s.opts.QuotaRefreshDebounce
115			}
116			if s.opts.QuotaRefreshStartupWait > 0 {
117				policy.startupWait = s.opts.QuotaRefreshStartupWait
118			}
119		}
120		return policy
121	}
