123	func (s *service) startPrimaryQuotaRefreshWorker() {
124		if s == nil || s.opts.QuotaRefreshInterval <= 0 {
125			return
126		}
127		ctx := s.opts.QuotaRefreshContext
128		if ctx == nil {
129			ctx = context.Background()
130		}
131		interval := s.opts.QuotaRefreshInterval
132		go func() {
133			ticker := time.NewTicker(interval)
134			defer ticker.Stop()
135			for {
136				select {
137				case <-ctx.Done():
138					return
139				case <-ticker.C:
140					s.ensurePrimaryQuotaRefresh(ctx, quotaRefreshAsync)
141				}
142			}
143		}()
144	}
