146	func (s *service) requestPrimaryQuotaRefresh(ctx context.Context, harnessName string, policy quotaRefreshPolicy) <-chan struct{} {
147		done := make(chan struct{})
148		if ctx == nil {
149			ctx = context.Background()
150		}
151		if ctx.Err() != nil {
152			close(done)
153			return nil
154		}
155	
156		now := time.Now()
157		primaryQuotaRefresh.mu.Lock()
158		if primaryQuotaRefresh.inFlight[harnessName] {
159			primaryQuotaRefresh.mu.Unlock()
160			close(done)
161			return nil
162		}
163		if last := primaryQuotaRefresh.lastAttempt[harnessName]; !last.IsZero() && now.Sub(last) < policy.debounce {
164			primaryQuotaRefresh.mu.Unlock()
165			close(done)
166			return nil
167		}
168		primaryQuotaRefresh.lastAttempt[harnessName] = now
169		primaryQuotaRefresh.inFlight[harnessName] = true
170		primaryQuotaRefresh.mu.Unlock()
171	
172		go func() {
173			defer close(done)
174			defer func() {
175				primaryQuotaRefresh.mu.Lock()
176				primaryQuotaRefresh.inFlight[harnessName] = false
177				primaryQuotaRefresh.mu.Unlock()
178			}()
179	
180			switch harnessName {
181			case "claude":
182				if qh, ok := s.harnessByName("claude").(harnesses.QuotaHarness); ok {
183					probeCtx, probeCancel := context.WithTimeout(ctx, policy.probeTimeout)
184					_, _ = qh.RefreshQuota(probeCtx)
185					probeCancel()
186				}
187			case "codex":
188				refreshCodexQuotaCache(ctx, policy.debounce, policy.probeTimeout)
189			}
190		}()
191		return done
192	}
