194	func waitForPrimaryQuotaRefreshes(waits []<-chan struct{}, timeout time.Duration) {
195		deadline := time.After(timeout)
196		for _, done := range waits {
197			select {
198			case <-done:
199			case <-deadline:
200				return
201			}
202		}
203	}
