253	// ListProviders returns providers known to the native fiz harness with live
254	// status, configured-default markers, and cooldown state.
255	func (s *service) ListProviders(ctx context.Context) ([]ProviderInfo, error) {
256		sc := s.opts.ServiceConfig
257		if sc == nil {
258			return nil, fmt.Errorf("service: no ServiceConfig provided; pass ServiceOptions.ServiceConfig")
259		}
260	
261		names := sc.ProviderNames()
262		defaultName := sc.DefaultProviderName()
263		cooldown := sc.HealthCooldown()
264		if cooldown <= 0 {
265			cooldown = 30 * time.Second
266		}
267	
268		type indexedInfo struct {
269			idx  int
270			info ProviderInfo
271		}
272		results := make([]indexedInfo, len(names))
273		var wg sync.WaitGroup
274	
275		for i, name := range names {
276			wg.Add(1)
277			go func(idx int, name string) {
278				defer wg.Done()
279	
280				entry, ok := sc.Provider(name)
281				if !ok {
282					results[idx] = indexedInfo{idx: idx, info: ProviderInfo{
283						Name:   name,
284						Status: "error: provider not found in config",
285					}}
286					return
287				}
288	
289				info := ProviderInfo{
290					Name:             name,
291					Type:             normalizeServiceProviderType(entry.Type),
292					BaseURL:          entry.BaseURL,
293					Endpoints:        append([]ServiceProviderEndpoint(nil), entry.Endpoints...),
294					Billing:          serviceProviderBilling(entry),
295					IncludeByDefault: serviceProviderDefaultInclusion(entry),
296					IsDefault:        name == defaultName,
297					DefaultModel:     entry.Model,
298				}
299	
300				if entry.ConfigError != "" {
301					capturedAt := time.Now().UTC()
302					info.Status = "error: invalid provider config"
303					info.EndpointStatus = providerEndpointStatusesFromProbe(entry, providerProbeResult{
304						status: "error: invalid provider config",
305						detail: entry.ConfigError,
306					}, capturedAt)
307					info.Auth = providerAuthStatus(entry, info.Status, capturedAt)
308					info.Quota = providerQuotaState(entry, capturedAt)
309					info.CooldownState = serviceProviderCooldown(sc, name, cooldown)
310					info.LastError = statusErrorDetail(info.Status, entry.ConfigError, "service provider config", capturedAt)
311					results[idx] = indexedInfo{idx: idx, info: info}
312					return
313				}
314	
315				probeCtx, cancel := context.WithTimeout(ctx, 5*time.Second)
316				defer cancel()
317				capturedAt := time.Now().UTC()
318				probe := probeProviderStatus(probeCtx, entry, capturedAt)
319				info.Status = probe.status
320				info.ModelCount = probe.modelCount
321				info.Capabilities = probe.caps
322				info.CooldownState = serviceProviderCooldown(sc, name, cooldown)
323				info.Auth = providerAuthStatus(entry, info.Status, capturedAt)
324				info.EndpointStatus = probe.endpointStatuses
325				info.Quota = providerQuotaState(entry, capturedAt)
326				lastErrorSource := "service provider config"
327				if len(info.EndpointStatus) > 0 {
328					lastErrorSource = info.EndpointStatus[0].Source
329				}
330				info.LastError = statusErrorDetail(info.Status, probe.detail, lastErrorSource, capturedAt)
331	
332				results[idx] = indexedInfo{idx: idx, info: info}
333			}(i, name)
334		}
335		wg.Wait()
336	
337		out := make([]ProviderInfo, len(names))
338		for _, r := range results {
339			out[r.idx] = r.info
340		}
341		return out, nil
342	}
