344	// HealthCheck triggers a fresh probe for the named health-check subject and updates internal state.
345	// health.Type is "harness" or "provider".
346	func (s *service) HealthCheck(ctx context.Context, health HealthTarget) error {
347		switch health.Type {
348		case "provider":
349			sc := s.opts.ServiceConfig
350			if sc == nil {
