400	func probeServiceProviderDetailed(ctx context.Context, entry ServiceProviderEntry) providerProbeResult {
401		switch entry.Type {
402		case "anthropic":
403			if entry.APIKey == "" {
404				return providerProbeResult{status: "error: api_key not configured", detail: "api_key not configured"}
405			}
406			// Anthropic does not expose an unauthenticated /v1/models list endpoint.
407			// Treat key presence as the connectivity signal.
408			return providerProbeResult{status: "connected", caps: providerCapabilities(entry)}
409	
410		case "openai", "openrouter", "lmstudio", "llama-server", "ds4", "omlx", "rapid-mlx", "vllm", "ollama", "minimax", "qwen", "zai", "":
411			if entry.BaseURL == "" {
412				return providerProbeResult{status: "error: base_url not configured", detail: "base_url not configured"}
413			}
414			n, err := discoverOpenAIModels(ctx, entry.BaseURL, entry.APIKey)
415			if err != nil {
416				msg := err.Error()
417				if serviceIsUnreachable(msg) {
418					return providerProbeResult{status: "unreachable", detail: serviceTrimError(msg)}
419				}
420				detail := serviceTrimError(msg)
421				return providerProbeResult{status: "error: " + detail, detail: detail}
422			}
423			return providerProbeResult{status: "connected", modelCount: n, caps: providerCapabilities(entry)}
424	
425		default:
426			detail := "unknown provider type " + entry.Type
427			return providerProbeResult{status: "error: " + detail, detail: detail}
428		}
429	}
