473	func shouldPreferProviderProbe(candidate, current providerProbeResult) bool {
474		return providerProbePriority(candidate.status) < providerProbePriority(current.status)
475	}
476	
477	func providerProbePriority(status string) int {
478		switch endpointStatus(status) {
479		case "connected":
480			return 0
481		case "unauthenticated":
482			return 1
483		case "unreachable":
484			return 2
485		default:
486			return 3
487		}
488	}
