490	// discoverOpenAIModels queries the /v1/models endpoint and returns the model count.
491	// This is a minimal inline version of provider/openai.DiscoverModels that avoids
492	// the import cycle (provider/openai imports the root agent package).
493	func discoverOpenAIModels(ctx context.Context, baseURL, apiKey string) (int, error) {
494		base := strings.TrimRight(baseURL, "/")
495		endpoint := base + "/models"
496	
497		req, err := http.NewRequestWithContext(ctx, http.MethodGet, endpoint, nil)
498		if err != nil {
499			return 0, fmt.Errorf("discovery: build request: %w", err)
500		}
501		req.Header.Set("Accept", "application/json")
502		if apiKey != "" {
503			req.Header.Set("Authorization", "Bearer "+apiKey)
504		}
505	
506		resp, err := http.DefaultClient.Do(req)
507		if err != nil {
508			return 0, err
509		}
510		defer resp.Body.Close()
511	
512		if resp.StatusCode != http.StatusOK {
513			body, _ := io.ReadAll(io.LimitReader(resp.Body, 512))
514			return 0, fmt.Errorf("discovery: %s returned HTTP %d: %s", endpoint, resp.StatusCode, strings.TrimSpace(string(body)))
515		}
516	
517		var mr struct {
518			Data []struct {
519				ID string `json:"id"`
520			} `json:"data"`
521		}
522		if err := json.NewDecoder(resp.Body).Decode(&mr); err != nil {
523			return 0, fmt.Errorf("discovery: decode response from %s: %w", endpoint, err)
524		}
525		return len(mr.Data), nil
526	}
