542	func serviceIsUnreachable(msg string) bool {
543		lower := strings.ToLower(msg)
544		return strings.Contains(lower, "connection refused") ||
545			strings.Contains(lower, "no such host") ||
546			strings.Contains(lower, "dial tcp") ||
547			strings.Contains(lower, "unreachable") ||
548			strings.Contains(lower, "connection reset") ||
549			strings.Contains(lower, "i/o timeout")
550	}
