624	func refreshCodexQuotaCache(_ context.Context, debounce, timeout time.Duration) {
625		cachePath, err := codexharness.CodexQuotaCachePath()
626		if err != nil {
627			return
628		}
629	
630		snap, _ := codexharness.ReadCodexQuotaFrom(cachePath)
631		if snap != nil && codexharness.IsCodexQuotaFresh(snap, time.Now(), debounce) && codexQuotaCacheComplete(snap) {
632			return
633		}
634	
635		if sessionSnap, ok := callHealthCheckCodexSessionQuotaReader(); ok && codexSessionQuotaUsable(sessionSnap, debounce) {
636			_ = codexharness.WriteCodexQuota(cachePath, *sessionSnap)
637			return
638		}
639	
640		windows, probeErr := callHealthCheckCodexQuotaRefresher(timeout)
641		if probeErr != nil || len(windows) == 0 {
642			return
643		}
644	
645		_ = codexharness.WriteCodexQuota(cachePath, codexharness.CodexQuotaSnapshot{
646			CapturedAt: time.Now().UTC(),
647			Windows:    windows,
648			Source:     "pty",
649		})
650	}
